python3 << 'EOF'
import json
import re

with open('manifest.json', 'r') as f:
    manifest = json.load(f)

with open('schema.json', 'r') as f:
    schema = json.load(f)

errors = []

# Check required fields
for field in schema['required']:
    if field not in manifest:
        errors.append(f"Missing required field: {field}")

# Check release format
if 'release' in manifest:
    if not isinstance(manifest['release'], str):
        errors.append(f"release must be a string, got {type(manifest['release'])}")
    elif not re.match(r'^v[0-9]+\.[0-9]+\.[0-9]+$', manifest['release']):
        errors.append(f"release must match pattern ^v[0-9]+\\.[0-9]+\\.[0-9]+$, got '{manifest['release']}'")

# Check components
if 'components' in manifest:
    comp = manifest['components']
    if not isinstance(comp, list):
        errors.append(f"components must be an array, got {type(comp)}")
    else:
        if len(comp) != 3:
            errors.append(f"components must have exactly 3 items, got {len(comp)}")

        for i, item in enumerate(comp):
            if not isinstance(item, dict):
                errors.append(f"component[{i}] must be an object, got {type(item)}")
            else:
                # Check required fields
                if 'name' not in item:
                    errors.append(f"component[{i}] missing required field 'name'")
                if 'version' not in item:
                    errors.append(f"component[{i}] missing required field 'version'")

                # Check name is string
                if 'name' in item and not isinstance(item['name'], str):
                    errors.append(f"component[{i}].name must be a string")
                elif 'name' in item and len(item['name']) == 0:
                    errors.append(f"component[{i}].name must have minLength 1")

                # Check version format
                if 'version' in item:
                    if not isinstance(item['version'], str):
                        errors.append(f"component[{i}].version must be a string")
                    elif not re.match(r'^[0-9]+\.[0-9]+\.[0-9]+$', item['version']):
                        errors.append(f"component[{i}].version must match pattern ^[0-9]+\\.[0-9]+\\.[0-9]+$, got '{item['version']}'")

                # Check no additional properties
                allowed = {'name', 'version'}
                for key in item.keys():
                    if key not in allowed:
                        errors.append(f"component[{i}] has unexpected property '{key}'")

# Check no additional properties at top level
allowed_top = {'release', 'components'}
for key in manifest.keys():
    if key not in allowed_top:
        errors.append(f"Unexpected top-level property '{key}'")

# Check uniqueness of components
names = [c.get('name') for c in manifest.get('components', [])]
if len(names) != len(set(names)):
    errors.append("Components must be unique")

if errors:
    print("✗ Validation failed:")
    for error in errors:
        print(f"  - {error}")
    exit(1)
else:
    print("✓ manifest.json is valid against schema.json")
EOF
